import React, { useEffect, useState } from 'react';
import { useDispatch, useSelector } from 'react-redux';
import { useSearchParams, useNavigate } from 'react-router-dom';
import { fetchProducts } from '../store/slices/productslice';
import ProductCard from '../components/product/productcart';
import LoadingSpinner from '../components/common/lodingspinner';
import { ChevronDown } from 'lucide-react';

const AllProductsPage = () => {
    const dispatch = useDispatch();
    const navigate = useNavigate();
    const [searchParams, setSearchParams] = useSearchParams();
    const [selectedCategory, setSelectedCategory] = useState(
        searchParams.get('category') || 'all'
    );
    const [sortBy, setSortBy] = useState(searchParams.get('sort') || 'newest');
    const [page, setPage] = useState(parseInt(searchParams.get('page')) || 1);

    const { items, loading, error, totalPages } = useSelector(
        (state) => state.products
    );

    // Categories list
    const categories = [
        { id: 'all', name: 'All Products', slug: 'all' },
        {
            id: 1,
            name: 'Sofas',
            slug: 'sofas',
            image: 'https://images.unsplash.com/photo-1555041469-a586c61ea9bc?w=400&h=400&fit=crop',
        },
        {
            id: 2,
            name: 'Beds',
            slug: 'beds',
            image: 'https://images.unsplash.com/photo-1505693416388-ac5ce068fe85?w=400&h=400&fit=crop',
        },
        {
            id: 3,
            name: 'Dining',
            slug: 'dining',
            image: 'https://images.unsplash.com/photo-1617806118233-18e1de247200?w=400&h=400&fit=crop',
        },
        {
            id: 4,
            name: 'Wardrobes',
            slug: 'wardrobes',
            image: 'https://images.unsplash.com/photo-1595428774223-ef52624120d2?w=400&h=400&fit=crop',
        },
        {
            id: 5,
            name: 'Study',
            slug: 'study',
            image: 'https://images.unsplash.com/photo-1518455027359-f3f8164ba6bd?w=400&h=400&fit=crop',
        },
    ];

    useEffect(() => {
        const params = {
            page,
            limit: 20,
        };

        if (selectedCategory !== 'all') {
            params.category = selectedCategory;
        }

        if (sortBy !== 'newest') {
            params.sort = sortBy;
        }

        dispatch(fetchProducts(params));

        // Update URL search params
        const newSearchParams = new URLSearchParams();
        if (selectedCategory !== 'all') {
            newSearchParams.set('category', selectedCategory);
        }
        if (sortBy !== 'newest') {
            newSearchParams.set('sort', sortBy);
        }
        if (page !== 1) {
            newSearchParams.set('page', page);
        }
        setSearchParams(newSearchParams);
    }, [dispatch, selectedCategory, sortBy, page, setSearchParams]);

    const handleCategoryChange = (categorySlug) => {
        setSelectedCategory(categorySlug);
        setPage(1);
    };

    const handleSortChange = (e) => {
        setSortBy(e.target.value);
        setPage(1);
    };

    const getDisplayCategory = () => {
        const cat = categories.find(
            (c) => c.slug === selectedCategory || c.id === selectedCategory
        );
        return cat?.name || 'All Products';
    };

    if (error) {
        return (
            <div className="bg-gray-50 min-h-screen py-12">
                <div className="container mx-auto px-4">
                    <div className="text-center">
                        <h1 className="text-3xl font-bold text-red-600 mb-4">
                            Error Loading Products
                        </h1>
                        <p className="text-gray-600 mb-6">{error}</p>
                        <button
                            onClick={() => window.location.reload()}
                            className="bg-brand-orange text-white px-6 py-3 rounded-lg font-semibold hover:bg-orange-600 transition"
                        >
                            Try Again
                        </button>
                    </div>
                </div>
            </div>
        );
    }

    return (
        <div className="bg-gray-50 min-h-screen">
            {/* Header */}
            <div className="bg-white border-b border-gray-100 py-6 md:py-8">
                <div className="container mx-auto px-4">
                    <div className="mb-4">
                        <button
                            onClick={() => navigate('/')}
                            className="text-gray-600 text-sm hover:text-brand-orange transition flex items-center gap-1"
                        >
                            ← Back to Home
                        </button>
                    </div>
                    <h1 className="text-3xl md:text-4xl font-bold text-gray-900 mb-2">
                        {getDisplayCategory()}
                    </h1>
                    <p className="text-gray-600">
                        Showing {items.length > 0 ? (page - 1) * 20 + 1 : 0} -{' '}
                        {Math.min(page * 20, items.length)} of {items.length} products
                    </p>
                </div>
            </div>

            <div className="container mx-auto px-4 py-8 md:py-12">
                <div className="grid grid-cols-12 gap-6 md:gap-8">
                    {/* Sidebar - Categories */}
                    <div className="col-span-12 md:col-span-3">
                        <div className="bg-white rounded-lg shadow-sm border border-gray-100 p-6">
                            <h3 className="text-lg font-bold text-gray-900 mb-4">
                                Categories
                            </h3>
                            <div className="space-y-3">
                                {categories.map((category) => (
                                    <button
                                        key={category.id}
                                        onClick={() => handleCategoryChange(category.slug)}
                                        className={`w-full text-left px-4 py-2 rounded-lg transition-all duration-200 font-medium text-sm ${selectedCategory === category.slug ||
                                                (selectedCategory === category.id && category.slug === 'all')
                                                ? 'bg-brand-orange text-white'
                                                : 'bg-gray-50 text-gray-700 hover:bg-gray-100'
                                            }`}
                                    >
                                        {category.name}
                                    </button>
                                ))}
                            </div>
                        </div>

                        {/* Filters */}
                        <div className="bg-white rounded-lg shadow-sm border border-gray-100 p-6 mt-6">
                            <h3 className="text-lg font-bold text-gray-900 mb-4">Sort By</h3>
                            <select
                                value={sortBy}
                                onChange={handleSortChange}
                                className="w-full px-4 py-2 border border-gray-200 rounded-lg text-gray-700 text-sm focus:outline-none focus:ring-2 focus:ring-brand-orange"
                            >
                                <option value="newest">Newest</option>
                                <option value="price_low">Price: Low to High</option>
                                <option value="price_high">Price: High to Low</option>
                                <option value="popular">Most Popular</option>
                                <option value="rating">Top Rated</option>
                            </select>
                        </div>
                    </div>

                    {/* Main Content - Products Grid */}
                    <div className="col-span-12 md:col-span-9">
                        {loading ? (
                            <div className="flex justify-center items-center py-20">
                                <LoadingSpinner />
                            </div>
                        ) : items.length === 0 ? (
                            <div className="bg-white rounded-lg shadow-sm border border-gray-100 p-12 text-center">
                                <h3 className="text-xl font-bold text-gray-900 mb-2">
                                    No Products Found
                                </h3>
                                <p className="text-gray-600 mb-6">
                                    Try adjusting your filters or browse other categories
                                </p>
                                <button
                                    onClick={() => handleCategoryChange('all')}
                                    className="bg-brand-orange text-white px-6 py-3 rounded-lg font-semibold hover:bg-orange-600 transition"
                                >
                                    View All Products
                                </button>
                            </div>
                        ) : (
                            <>
                                {/* Products Grid */}
                                <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-4 md:gap-6 mb-8">
                                    {items.map((product) => (
                                        <ProductCard key={product._id} product={product} />
                                    ))}
                                </div>

                                {/* Pagination */}
                                {totalPages > 1 && (
                                    <div className="flex justify-center items-center gap-2 py-8">
                                        <button
                                            onClick={() => setPage(Math.max(1, page - 1))}
                                            disabled={page === 1}
                                            className="px-4 py-2 border border-gray-200 rounded-lg text-gray-700 hover:border-brand-orange hover:text-brand-orange disabled:opacity-50 disabled:cursor-not-allowed transition"
                                        >
                                            Previous
                                        </button>

                                        {Array.from({ length: totalPages }, (_, i) => i + 1).map(
                                            (p) => (
                                                <button
                                                    key={p}
                                                    onClick={() => setPage(p)}
                                                    className={`px-3 py-2 rounded-lg transition-all duration-200 font-medium ${page === p
                                                            ? 'bg-brand-orange text-white'
                                                            : 'border border-gray-200 text-gray-700 hover:border-brand-orange hover:text-brand-orange'
                                                        }`}
                                                >
                                                    {p}
                                                </button>
                                            )
                                        )}

                                        <button
                                            onClick={() => setPage(Math.min(totalPages, page + 1))}
                                            disabled={page === totalPages}
                                            className="px-4 py-2 border border-gray-200 rounded-lg text-gray-700 hover:border-brand-orange hover:text-brand-orange disabled:opacity-50 disabled:cursor-not-allowed transition"
                                        >
                                            Next
                                        </button>
                                    </div>
                                )}
                            </>
                        )}
                    </div>
                </div>
            </div>
        </div>
    );
};

export default AllProductsPage;
